// Build email body with Google Form link
const callerName = items[0].json.caller_name || 'there';
const callerEmail = items[0].json.caller_email || '';
const callId = items[0].json.call_id || '';

// Google Form public URL
const FORM_URL = 'https://docs.google.com/forms/d/1nXAAS4HKmuoofX9dqK5vF_llri1zEEThAyOJBI-midk/viewform';

const emailSubject = 'Equity Insurance - Your Quote Form';

const emailBody = `<div style="font-family: Arial, sans-serif; max-width: 600px; margin: 0 auto;">
  <h2 style="color: #2c5282;">Aloha ${callerName}!</h2>
  <p>Thank you for calling Equity Insurance. As discussed, here's the link to our quick quote form to help our agent get your quote together even faster:</p>
  <p style="text-align: center; margin: 30px 0;">
    <a href="${FORM_URL}" style="background-color: #2c5282; color: white; padding: 14px 28px; text-decoration: none; border-radius: 6px; font-size: 16px;">Fill Out Quote Form</a>
  </p>
  <p>Or copy and paste this link: <a href="${FORM_URL}">${FORM_URL}</a></p>
  <p>If you have any questions, don't hesitate to call us back at <strong>(808) 593-7746</strong>.</p>
  <p>Mahalo!<br>The Equity Insurance Team<br>Honolulu, Hawaii</p>
</div>`;

return [{
  json: {
    to: callerEmail,
    subject: emailSubject,
    body: emailBody,
    call_id: callId,
    caller_name: callerName,
    form_url: FORM_URL
  }
}];

